import streamlit as stfrom streamlit_gsheets import GSheetsConnectionimport pandas as pdfrom datetime import datetime, timedeltaimport urllib.parseimport plotly.express as pximport warnings# Gereksiz uyarıları gizlewarnings.filterwarnings("ignore")# --- 1. SAYFA AYARLARI ---st.set_page_config(    page_title="Bostanlı Çözüm VIP",     layout="wide",     page_icon="🏫",    initial_sidebar_state="collapsed" )# Arayüz temizleme CSSst.markdown("""    <style>    #MainMenu {visibility: hidden;}    footer {visibility: hidden;}    header {visibility: hidden;}    .stDeployButton {display:none;}    .stTabs [data-baseweb="tab-list"] {        gap: 10px;        background-color: #f0f2f6;        padding: 10px;        border-radius: 10px;    }    .stTabs [data-baseweb="tab"] {        height: 50px;        white-space: pre-wrap;        background-color: #ffffff;        border-radius: 5px;        padding: 10px 20px;        font-weight: bold;    }    </style>    """, unsafe_allow_html=True)# --- 2. ÇİFTLİ ŞİFRE SİSTEMİ ---def check_password():    if "user_role" not in st.session_state:        st.title("🔐 Kurumsal Yönetim Paneli")        pwd = st.text_input("Giriş Şifresi", type="password")        if st.button("Sisteme Giriş Yap"):            if pwd == "cozum35":                st.session_state["user_role"] = "admin"                st.rerun()            elif pwd == "personel35":                st.session_state["user_role"] = "staff"                st.rerun()            else:                st.error("❌ Hatalı şifre. Lütfen tekrar deneyin.")        return False    return Trueif check_password():    conn = st.connection("gsheets", type=GSheetsConnection)    role = st.session_state["user_role"]    def wa_link(tel, mesaj):        tel_str = str(tel).replace(" ", "").replace("-", "").replace("(", "").replace(")", "")        if tel_str.startswith("0"): tel_str = "90" + tel_str[1:]        elif not tel_str.startswith("90"): tel_str = "90" + tel_str        return f"https://wa.me/{tel_str}?text={urllib.parse.quote(mesaj)}"    # --- 3. YETKİYE GÖRE TABLARI TANIMLA ---    st.title(f"🏫 Bostanlı Çözüm VIP ({'Kurucu' if role == 'admin' else 'Personel'} Paneli)")        if role == "admin":        # Kurucu her şeyi görür        t1, t2, t3, t4, t5 = st.tabs(["📞 Veli Görüşmeleri", "💰 Kasa İşlemleri", "🚨 Günlük Olaylar", "📊 Kurucu Raporu", "📈 Gelişmiş Analiz"])    else:        # Personel sadece ilk 3 sekmeyi görür        t1, t2, t3 = st.tabs(["📞 Veli Görüşmeleri", "💰 Kasa İşlemleri", "🚨 Günlük Olaylar"])    # --- 📞 TAB 1: VELİ GÖRÜŞMELERİ (Herkes Görür) ---    with t1:        st.header("📞 Veli Görüşme Kayıt")        try:            df_v = conn.read(worksheet="gorusmeler", ttl=0)        except:            df_v = pd.DataFrame(columns=["Tarih", "Ad Soyad", "Telefon", "Konu", "Durum", "Notlar"])                with st.form("v_form", clear_on_submit=True):            v_tarih = st.date_input("Görüşme Tarihi", datetime.now(), format="DD/MM/YYYY")            c1, c2 = st.columns(2)            v_ad = c1.text_input("Veli / Öğrenci Ad Soyad *")            v_tel = c1.text_input("Telefon Numarası *")            v_konu = c2.selectbox("Konu *", ["Seçiniz...", "Yeni Kayıt", "YKS Hazırlık", "LGS Hazırlık", "Ara Sınıf Hazırlık", "Online Kamp", "Yüz Yüze Kamp", "Kayıt Silme", "Diğer"])            v_durum = c2.selectbox("Durum *", ["Seçiniz...", "Beklemede", "Olumlu", "Olumsuz", "Kayıt Tamamlandı", "İptal"])            v_not = st.text_area("Görüşme Notları *")                        if st.form_submit_button("Kaydı Tamamla"):                if v_ad == "" or v_tel == "" or v_konu == "Seçiniz..." or v_durum == "Seçiniz..." or v_not == "":                    st.error("⚠️ Eksik alanları doldurun!")                else:                    new = pd.DataFrame([{"Tarih": v_tarih.strftime("%Y-%m-%d"), "Ad Soyad": v_ad, "Telefon": v_tel, "Konu": v_konu, "Durum": v_durum, "Notlar": v_not}])                    conn.update(worksheet="gorusmeler", data=pd.concat([df_v, new], ignore_index=True))                    st.success(f"✅ {v_ad} kaydedildi.")    # --- 💰 TAB 2: KASA İŞLEMLERİ (Herkes Görür) ---    with t2:        st.header("💰 Kasa Giriş / Çıkış")        try:            df_k = conn.read(worksheet="kasa", ttl=0)        except:            df_k = pd.DataFrame(columns=["Tarih", "Tip", "Kategori", "Miktar", "Detay"])        k_tarih = st.date_input("İşlem Tarihi", datetime.now(), format="DD/MM/YYYY")        k_tip = st.radio("İşlem Türü Seçiniz:", ["Gelir (Tahsilat)", "Gider (Ödeme)"], horizontal=True)                if k_tip == "Gelir (Tahsilat)":            k_kalemler = ["Seçiniz...", "Aidat Ödemesi", "Yayın Paketi Ödemesi", "Özel Ders Ödemesi", "Deneme Kulübü Ödemesi", "Kamp Ödemesi", "Diğer Gelir"]        else:            k_kalemler = ["Seçiniz...", "Kira", "Maaş", "Deneme Ücreti", "Kargo", "Elektrik", "Su", "İnternet", "Sabit Telefon", "Cep Telefonu", "Market Alışverişi", "Reklam", "Diğer Gider"]                    k_kat = st.selectbox("Kategori Seçin *", k_kalemler)        k_tutar = st.number_input("Tutar (TL) *", min_value=0.0, step=10.0)        k_detay = st.text_input("Açıklama *")        if st.button("İşlemi Kasaya Kaydet"):            if k_kat == "Seçiniz..." or k_tutar <= 0 or k_detay == "":                st.error("⚠️ Lütfen bilgileri eksiksiz girin!")            else:                new_k = pd.DataFrame([{"Tarih": k_tarih.strftime("%Y-%m-%d"), "Tip": k_tip, "Kategori": k_kat, "Miktar": k_tutar, "Detay": k_detay}])                conn.update(worksheet="kasa", data=pd.concat([df_k, new_k], ignore_index=True))                st.success(f"💰 {k_kat} kaydedildi.")    # --- 🚨 TAB 3: GÜNLÜK OLAYLAR (Herkes Görür) ---    with t3:        st.header("🚨 Günlük Olay Paneli")        try:            df_o = conn.read(worksheet="olaylar", ttl=0)        except:            df_o = pd.DataFrame(columns=["Tarih", "Olay Tipi", "Detay"])                    with st.form("olay_form", clear_on_submit=True):            o_tarih = st.date_input("Olay Tarihi", datetime.now(), format="DD/MM/YYYY")            o_tip = st.selectbox("Durum Tipi *", ["Seçiniz...", "Acil Durum", "Resmi Denetim", "Veli Şikayeti", "Teknik Arıza", "Önemli Ziyaretçi", "Diğer"])            o_detay = st.text_area("Olay Detayı *")                        if st.form_submit_button("Olayı Kaydet"):                if o_tip == "Seçiniz..." or o_detay == "":                    st.error("⚠️ Boş bırakmayın!")                else:                    new_o = pd.DataFrame([{"Tarih": o_tarih.strftime("%Y-%m-%d"), "Olay Tipi": o_tip, "Detay": o_detay}])                    conn.update(worksheet="olaylar", data=pd.concat([df_o, new_o], ignore_index=True))                    st.success("✅ Olay kaydedildi.")    # --- 📊 TAB 4: KURUCU RAPORU (SADECE KURUCU) ---    if role == "admin":        with t4:            st.header("📊 Günlük Detaylı Rapor")            t_sec_raw = st.date_input("Rapor Tarihi Seç", datetime.now(), format="DD/MM/YYYY")            t_sec = t_sec_raw.strftime("%Y-%m-%d")                        try:                dv = conn.read(worksheet="gorusmeler", ttl=0)                dk = conn.read(worksheet="kasa", ttl=0)                do = conn.read(worksheet="olaylar", ttl=0)                                dv['Tarih'] = dv['Tarih'].astype(str)                dk['Tarih'] = dk['Tarih'].astype(str)                do['Tarih'] = do['Tarih'].astype(str)                                dv_b = dv[dv['Tarih'].str.contains(t_sec, na=False)]                dk_b = dk[dk['Tarih'].str.contains(t_sec, na=False)]                do_b = do[do['Tarih'].str.contains(t_sec, na=False)]                                dk_b['Miktar'] = pd.to_numeric(dk_b['Miktar'], errors='coerce').fillna(0)                gelir_df = dk_b[dk_b['Tip'] == 'Gelir (Tahsilat)']                gider_df = dk_b[dk_b['Tip'] == 'Gider (Ödeme)']                t_gelir = gelir_df['Miktar'].sum()                t_gider = gider_df['Miktar'].sum()                                c1, c2, c3, c4 = st.columns(4)                c1.metric("Görüşme", len(dv_b))                c2.metric("Gelir", f"{t_gelir:,.0f} TL")                c3.metric("Gider", f"{t_gider:,.0f} TL")                c4.metric("Net", f"{t_gelir - t_gider:,.0f} TL", delta=float(t_gelir - t_gider))                if not do_b.empty:                    st.warning("⚠️ Bugün Kaydedilen Önemli Olaylar")                    st.table(do_b[['Olay Tipi', 'Detay']])                st.divider()                col1, col2 = st.columns(2)                with col1:                    st.subheader("💰 Gelirler")                    st.dataframe(gelir_df[['Kategori', 'Miktar', 'Detay']], use_container_width=True) if not gelir_df.empty else st.info("Yok.")                with col2:                    st.subheader("💸 Giderler")                    st.dataframe(gider_df[['Kategori', 'Miktar', 'Detay']], use_container_width=True) if not gider_df.empty else st.info("Yok.")                msg = f"*🏫 BOSTANLI ÇÖZÜM VIP ({t_sec_raw.strftime('%d.%m.%Y')})*\n\n"                msg += f"*📊 ÖZET*\n📞 Görüşme: {len(dv_b)}\n💰 Gelir: {t_gelir:,.0f} TL\n💸 Gider: {t_gider:,.0f} TL\n📈 Net: {t_gelir - t_gider:,.0f} TL\n"                st.markdown(f'[(📲 WhatsApp ile Gönder)]({wa_link("905492551912", msg)})')            except Exception as e:                st.error(f"Rapor hatası: {e}")    # --- 📈 TAB 5: ANALİZ (SADECE KURUCU) ---    if role == "admin":        with t5:            st.header("📈 Finansal Analiz")            try:                dk = conn.read(worksheet="kasa", ttl=0)                dk['Miktar'] = pd.to_numeric(dk['Miktar'], errors='coerce').fillna(0)                dk['Tarih'] = pd.to_datetime(dk['Tarih'], errors='coerce')                dk = dk.dropna(subset=['Tarih'])                col_f1, col_f2 = st.columns(2)                bas_tar = col_f1.date_input("Başlangıç", datetime.now() - timedelta(days=90), format="DD/MM/YYYY")                bit_tar = col_f2.date_input("Bitiş", datetime.now(), format="DD/MM/YYYY")                mask = (dk['Tarih'].dt.date >= bas_tar) & (dk['Tarih'].dt.date <= bit_tar)                df_f = dk.loc[mask]                                if not df_f.empty:                    c_g1, c_g2 = st.columns(2)                    c_g1.plotly_chart(px.pie(df_f[df_f['Tip'] == 'Gelir (Tahsilat)'], values='Miktar', names='Kategori', title="Gelir Dağılımı"), use_container_width=True)                    c_g2.plotly_chart(px.pie(df_f[df_f['Tip'] == 'Gider (Ödeme)'], values='Miktar', names='Kategori', title="Gider Dağılımı"), use_container_width=True)                else: st.warning("Veri yok.")            except: st.error("Analiz hatası.")    # --- 🚪 OTURUMU KAPAT ---    st.sidebar.divider()    if st.sidebar.button("Güvenli Çıkış"):        del st.session_state["user_role"]        st.rerun()